#include <algorithm>
#include <sstream>
#include <string>
#include <vector>

string reverseWords(string s) {
    stringstream ss(s);
    vector<string> words;
    string word;

    while (ss >> word) {
        words.push_back(word);
    }

    for (int i = 0; i < words.size(); i++) {
        reverse(words[i].begin(), words[i].end());
    }

    string result = "";
    for (int i = 0; i < words.size(); i++) {
        result += words[i] + " ";
    }

    return result;
}
```

